#!/usr/bin/env python3
"""Generate 100+ pages for each of 10 framework sections with rich content."""
import os, re

BASE = "/home/admin1/projects/ErrorCode.excellentwiki.com/content/frameworks"

def slugify(t):
    s = re.sub(r"[^a-z0-9]+", "-", t.lower()).strip("-")
    return s

def get_existing(d):
    p = os.path.join(BASE, d)
    return set(f[:-3] for f in os.listdir(p) if f.endswith(".md")) if os.path.isdir(p) else set()

def write_page(fw, prefix, name, title, desc, causes, fix, code):
    slug = f"{prefix}-{slugify(title)}"
    fp = os.path.join(BASE, fw, f"{slug}.md")
    with open(fp, "w") as f:
        f.write(f"""---
title: "[Solution] {name} {title}"
description: "{desc}"
frameworks: ["{fw}"]
error-types: ["framework-error"]
severities: ["error"]
---

{desc}

## Common Causes

{causes}

## How to Fix

{fix}

## Example

{code}
""")
    return slug

