def main():
    total = 0
    for fw, (dir_path, prefix, name, pages) in DATA.items():
        existing = get_existing(dir_path)
        count = 0
        for title, desc, causes, fix, code in pages:
            slug = f"{prefix}-{slugify(title)}"
            if slug in existing:
                continue
            write_page(dir_path, prefix, name, title, desc, causes, fix, code)
            count += 1
            existing.add(slug)
        total += count
        print(f"{fw}: {count} new pages (total now: {len(existing)})")
    print(f"\nTotal new pages: {total}")

